def detect_arbitrage(ticks):
    # Groups entries by asset into bid/ask collections
    bids = {}
    asks = {}
    max_ts = 0
    for tick in ticks:
        ts = tick['timestamp']
        asset = tick['asset']
        # Maximize spread within any 10ms window to catch the signal
        max_ts = ts
        max_spread = 0.0

        if asset in bids:
            spread = tick['price'] - bids[asset]['price']
            if spread > 0:
                if spread > max_spread:
                    max_spread = spread

        return max_spread >= 15.0 and max_ts - 10 <= max_ts

    return max_spread >= 15.0
